import React, { Component } from "react";

class Footer extends Component {
  render() {
    if (this.props.sharedBasicInfo) {
      var networks = this.props.sharedBasicInfo.social.map(function (network) {
        return (
          <span key={network.name} className="m-4">
            <a 
              href={network.url} 
              target="_blank" 
              rel="noopener noreferrer"
              style={{ 
                color: "white", 
                fontSize: "30px", // Made icons slightly larger
                transition: "all 0.3s ease" 
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.color = "#AE944F";
                e.currentTarget.style.transform = "scale(1.2)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.color = "white";
                e.currentTarget.style.transform = "scale(1)";
              }}
            >
              <i className={network.class}></i>
            </a>
          </span>
        );
      });
    }

    return (
      // Added id="contact" here so the header button knows where to go
      <footer id="contact" style={{ 
        background: "#121212", 
        padding: "80px 0 50px 0", // Increased top padding for better spacing
        marginTop: "0px"
      }}>
        <div className="col-md-12 text-center">
          {/* Added a Section Title to make it clear this is the contact area */}
          <h2 style={{ 
            color: "white", 
            marginBottom: "40px", 
            fontWeight: "600",
            textTransform: "uppercase",
            letterSpacing: "2px",
            fontSize: "1.5rem"
          }}>
            Get In Touch
          </h2>

          <div className="social-links" style={{ textAlign: "center", marginBottom: "50px" }}>
            {networks}
          </div>

          <div className="copyright py-4 text-center">
            <div className="container">
              <small style={{ 
                color: "white", 
                opacity: 0.5, 
                fontSize: "14px"
              }}>
                Copyright &copy;{" "}
                {this.props.sharedBasicInfo
                  ? this.props.sharedBasicInfo.name
                  : "???"}
              </small>
            </div>
          </div>
        </div>
      </footer>
    );
  }
}

export default Footer;
